import { useEffect, useRef } from 'react';
import { mainButton } from '@telegram-apps/sdk-react';

import { useMainButtonAvailable } from '@/hooks/useTelegramButtonsAvailable';
import { hapticButton } from '@/utils/haptic';

export interface UseMainButtonOptions {
  /** Button label */
  text: string;
  /** Whether the button is clickable */
  isEnabled?: boolean;
  /** Called when user taps the main button */
  onClick: () => void;
  /** Show the button (default true when options are provided) */
  isVisible?: boolean;
  /** Shine effect (default false) */
  hasShineEffect?: boolean;
  /** Show loading spinner on the button */
  isLoading?: boolean;
}

/**
 * Binds Telegram Main Button to the given text, enabled state and click handler.
 * No-op when Main Button is not available (e.g. outside Mini App).
 * Cleans up on unmount or when dependencies change.
 */
export function useMainButton(options: UseMainButtonOptions | null) {
  const available = useMainButtonAvailable();
  const onClickRef = useRef(options?.onClick);
  onClickRef.current = options?.onClick;

  useEffect(() => {
    if (!available || !options) {
      if (available) mainButton.setParams({ isVisible: false });
      return;
    }

    const {
      text,
      isEnabled = true,
      isVisible = true,
      hasShineEffect = false,
      isLoading = false,
    } = options;

    mainButton.setParams({
      text,
      isVisible,
      isEnabled,
      hasShineEffect,
      isLoaderVisible: isLoading,
    });

    const off = mainButton.onClick(() => {
      hapticButton();
      onClickRef.current?.();
    });

    return () => {
      mainButton.setParams({ isVisible: false, isLoaderVisible: false });
      off();
    };
  }, [
    available,
    options?.text,
    options?.isEnabled,
    options?.isVisible,
    options?.hasShineEffect,
    options?.isLoading,
  ]);

  useEffect(() => {
    if (!available || !options) return;
    mainButton.setParams({ isEnabled: options.isEnabled ?? true });
  }, [available, options?.isEnabled]);
}
