/**
 * Shared chart colors based on Telegram theme CSS variables.
 *
 * Values are strings like `var(--tg-theme-link-color)` which Chart.js
 * accepts directly for border/background colors. This keeps charts
 * visually in sync with Telegram UI (light/dark themes, custom colors).
 *
 * Reference:
 * https://docs.telegram-mini-apps.com/platform/theming
 */
export const CHART_COLORS = {
  /** Main \"principal\" series (e.g. тело долга). */
  principal: 'var(--tg-theme-link-color)',
  principalFill: 'var(--tg-theme-link-color)',

  /** Interest / overpayment series. Uses destructive text color. */
  interest: 'var(--tg-theme-destructive-text-color)',
  interestFill: 'var(--tg-theme-destructive-text-color)',

  /** Balance curve and \"with early payments\" bars. Accent or button color. */
  balance: 'var(--tg-theme-accent-text-color)',
  balanceFill: 'var(--tg-theme-accent-text-color)',

  /** Extra payments share in doughnut / pie charts. */
  extraPayment: 'var(--tg-theme-button-color)',

  /** Baseline vs modified comparison bars. */
  original: 'var(--tg-theme-destructive-text-color)',
  withEarlyPayments: 'var(--tg-theme-accent-text-color)',
} as const;
